<?php
 namespace WPAICG\Chat\Core\AIService\GenerateResponse; use WP_Error; if (!defined('ABSPATH')) { exit; } function validate_request_logic( ?\WPAICG\Core\AIPKit_AI_Caller $ai_caller, string $user_message, ?array $image_inputs_for_service, array $bot_settings ): bool|WP_Error { if (!$ai_caller) { return new WP_Error('ai_caller_missing_validation', 'AI Caller component is not available for request validation.'); } if (empty($user_message) && empty($image_inputs_for_service)) { return new WP_Error('empty_content_validation', __('User message or image cannot be empty.', 'gpt3-ai-content-generator')); } if (empty($bot_settings['bot_id'])) { return new WP_Error('missing_bot_id_validation', __('Bot ID is missing in settings for request validation.', 'gpt3-ai-content-generator')); } return true; } 